1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return an empty grid when given an empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a cell alive that has exactly two live neighbors (survival)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toEqual(
17	      expect.arrayContaining([[1, 0]])
18	    );
19	  });
20	  it.todo("should keep a cell alive that has exactly three live neighbors (survival)");
21	  it.todo("should bring a dead cell to life when it has exactly three live neighbors (reproduction)");
22	  it.todo("should kill a cell that has four live neighbors (overpopulation)");
23	  it.todo("should maintain a block still life (2x2 square) unchanged across a generation");
24	  it.todo("should oscillate a blinker (three cells in a line) to its alternate phase");
25	});
26

1	export function nextGeneration(livingCells: [number, number][]): [number, number][] {
2	  if (livingCells.length === 0) return [];
3	
4	  const alive = new Set(livingCells.map(([x, y]) => `${x},${y}`));
5	  const candidates = new Set<string>();
6	
7	  for (const [x, y] of livingCells) {
8	    for (let dx = -1; dx <= 1; dx++) {
9	      for (let dy = -1; dy <= 1; dy++) {
10	        candidates.add(`${x + dx},${y + dy}`);
11	      }
12	    }
13	  }
14	
15	  const result: [number, number][] = [];
16	
17	  for (const key of candidates) {
18	    const [x, y] = key.split(",").map(Number);
19	    let neighbors = 0;
20	    for (let dx = -1; dx <= 1; dx++) {
21	      for (let dy = -1; dy <= 1; dy++) {
22	        if (dx === 0 && dy === 0) continue;
23	        if (alive.has(`${x + dx},${y + dy}`)) neighbors++;
24	      }
25	    }
26	    if (alive.has(key)) {
27	      if (neighbors === 2 || neighbors === 3) result.push([x, y]);
28	    } else {
29	      if (neighbors === 3) result.push([x, y]);
30	    }
31	  }
32	
33	  return result;
34	}
